VALUES
  ('promotion-4c199b1b-moex-00032', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-112-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '甲對限制行為能力人乙負有債務。下列敘述何者正確？', '["乙得向甲請求履行債務", "乙受甲之清償，應經乙之法定代理人同意", "縱使甲因清償而為所有權移轉，乙仍無法取得該標的之所有權", "甲清償後，得向乙請求不當得利返還給付標的所有權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00033', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-112-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '下列關於物之成分的敘述，何者錯誤？', '["房屋之棟樑為房屋之成分", "土地上種植之樹木為土地之成分", "外加於腳踏車之防盜鎖為腳踏車之成分", "安裝於房屋之門框為房屋之成分 13540 13740"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00034', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-112-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '下列何者屬於民法上之「一物」？', '["牧場主人所有之一群牛", "餐廳冰箱中之一打汽水", "銀行員遞交經捆綁成一疊之千元紙鈔", "超級市場貨架上陳列之一包白米"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00035', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-112-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '甲有 A 地，其與乙通謀虛偽意思表示出賣 A 地並移轉所有權於乙，乙又將該地出賣並移轉所有 權於第三人丙。下列敘述何者錯誤？', '["倘若丙不知甲、乙間之通謀虛偽意思表示，則丙取得A地之所有權", "倘若丙不知甲、乙間之通謀虛偽意思表示，將A地再出賣並移轉所有權於丁，丁明知甲、乙間 有通謀虛偽意思表示，則丁取得A地之所有權", "倘若丙明知甲、乙間有通謀虛偽意思表示，則丙取得A地之所有權", "倘若丙明知甲、乙間有通謀虛偽意思表示，並將該地再出賣且移轉所有權於丁，丁不知甲、乙 間之通謀虛偽意思表示，則丁取得A地之所有權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00036', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-112-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '甲與乙訂立買賣契約，將其所有之A屋出賣於乙，在甲將A屋交付於乙之前，A屋因地震倒塌。 下列敘述何者錯誤？', '["甲免給付A屋於乙之義務", "甲對乙負損害賠償之義務", "乙免給付價金於甲之義務", "乙得請求甲返還已給付之價金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00037', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-112-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '甲將其對乙基於雙方買賣契約所取得之價金請求權（A債權）讓與丙，而在甲將該情事通知乙時， 乙亦對甲另有因消費借貸而生之B金錢債權。如B債權之清償期先於A債權，下列敘述何者正 確？', '["乙得對甲主張抵銷", "甲得對乙主張抵銷", "乙得對丙主張抵銷", "丙得代甲對乙主張抵銷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00038', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-112-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '甲為A車之所有人，乙承租甲之A車，獨自駕車環島旅行，途中不慎撞傷路人丙，於是丙依民法 第191條之2規定請求損害賠償。下列敘述何者正確？', '["甲應證明，於防止損害之發生，已盡相當之注意，始得免責", "乙應證明，於防止損害之發生，已盡相當之注意，始得免責", "丙應證明，甲於損害之發生未盡相當之注意，始得請求賠償", "丙應證明，乙於損害之發生未盡相當之注意，始得請求賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00039', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-112-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '甲將其名下之土地出賣於乙，已收清價金，並交付該地，惟未辦理所有權移轉登記。嗣該地經丙 市政府依法徵收，其地價補償費由甲領取完畢。下列敘述何者正確？', '["乙得依不當得利之規定，向甲請求返還地價補償費", "因乙已占有該地，且已付清價金，丙應負通知乙領取地價補償費之義務", "乙得依關於不當得利之規定，請求甲返還其已付清之價金", "乙不得向甲請求交付其所受領之地價補償費"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00040', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-112-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '依民法規定，下列何者並非要物契約？', '["和解契約", "使用借貸", "消費借貸", "寄託契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00041', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-112-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '甲僱用乙擔任公司會計，甲得知乙擔任甲公司企業工會之理事長後非常不高興，遂無預警解僱乙， 並要求乙當天即完成工作交接、收拾個人物品，及交出識別證不准乙再進入公司。乙認為甲係違 法解僱，甲乙間之僱傭關係仍存在，乙仍欲提供勞務，並請求甲支付報酬。關於甲乙間之權利義 務關係，下列敘述何者錯誤？', '["甲既已解僱乙，乃預示拒絕受領之意思，故乙得以準備給付勞務之事情通知甲，以代提出", "若乙現實提出勞務給付，但甲仍拒絕受領，則乙得依民法第487條有關僱用人受領勞務遲延之 規定，請求甲給付報酬", "若乙現實提出勞務給付，甲雖拒絕受領，但仍給付報酬者，甲日後得請求乙補服勞務", "若甲因受領遲延而依乙之請求支付報酬時，乙轉向他處服勞務所取得之利益，甲得由報酬額內扣除之 13540 13740"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL)
